/* ContactForm — form with Cloudflare Turnstile spam protection and
   client-side fetch submission to /api/contact. */
const siteKey = import.meta.env.PUBLIC_TURNSTILE_SITE_KEY ?? '';
---

<form class="contact-form" novalidate>
  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-name">Name</label>
    <input
      class="contact-form__input"
      type="text"
      id="contact-name"
      name="name"
      required
      minlength="2"
      autocomplete="name"
      placeholder="Your name"
    />
    <span class="contact-form__error" data-field="name"></span>
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-email">Email</label>
    <input
      class="contact-form__input"
      type="email"
      id="contact-email"
      name="email"
      required
      autocomplete="email"
      placeholder="you@example.com"
    />
    <span class="contact-form__error" data-field="email"></span>
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-message">Message</label>
    <textarea
      class="contact-form__input contact-form__textarea"
      id="contact-message"
      name="message"
      required
      minlength="10"
      rows="5"
      placeholder="How can we help?"
    ></textarea>
    <span class="contact-form__error" data-field="message"></span>
  </div>

  <!-- Cloudflare Turnstile widget -->
  <div class="cf-turnstile" data-sitekey={siteKey} data-theme="light"></div>
  <span class="contact-form__error" data-field="turnstileToken"></span>

  <button class="contact-form__submit" type="submit">
    <span class="contact-form__submit-text">Send Message</span>
    <span class="contact-form__spinner" aria-hidden="true"></span>
  </button>

  <!-- General error banner -->
  <div class="contact-form__banner contact-form__banner--error" role="alert" hidden></div>

  <!-- Success message -->
  <div class="contact-form__banner contact-form__banner--success" role="status" hidden></div>
</form>

<!-- Turnstile script — loaded async to avoid blocking -->
<script is:inline src="https://challenges.cloudflare.com/turnstile/v0/api.js" async defer></script>

<script is:inline>
(function () {
  const form = document.querySelector('.contact-form');
  if (!form) return;

  const submitBtn = form.querySelector('.contact-form__submit');
  const submitText = form.querySelector('.contact-form__submit-text');
  const spinner = form.querySelector('.contact-form__spinner');
  const errorBanner = form.querySelector('.contact-form__banner--error');
  const successBanner = form.querySelector('.contact-form__banner--success');

  /* ---- Helpers ---- */

  function showFieldError(field, msg) {
    const el = form.querySelector('[data-field="' + field + '"]');
    if (el) {
      el.textContent = msg;
      el.hidden = false;
    }
    const input = form.querySelector('[name="' + field + '"]');
    if (input) input.classList.add('contact-form__input--error');
  }

  function clearErrors() {
    form.querySelectorAll('.contact-form__error').forEach(function (el) {
      el.textContent = '';
      el.hidden = true;
    });
    form.querySelectorAll('.contact-form__input--error').forEach(function (el) {
      el.classList.remove('contact-form__input--error');
    });
    errorBanner.hidden = true;
    errorBanner.textContent = '';
  }

  function setLoading(loading) {
    submitBtn.disabled = loading;
    submitText.textContent = loading ? 'Sending…' : 'Send Message';
    spinner.hidden = !loading;
  }

  /* ---- Client-side validation ---- */

  var EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  function validate() {
    var errors = [];
    var name = form.querySelector('[name="name"]').value.trim();
    var email = form.querySelector('[name="email"]').value.trim();
    var message = form.querySelector('[name="message"]').value.trim();

    if (name.length < 2) {
      errors.push({ field: 'name', message: 'Name is required (min 2 characters)' });
    }
    if (!EMAIL_RE.test(email)) {
      errors.push({ field: 'email', message: 'A valid email address is required' });
    }
    if (message.length < 10) {
      errors.push({ field: 'message', message: 'Message is required (min 10 characters)' });
    }
    return errors;
  }

  /* ---- Submission ---- */

  form.addEventListener('submit', async function (e) {
    e.preventDefault();
    clearErrors();
    successBanner.hidden = true;

    /* Client-side validation */
    var clientErrors = validate();
    if (clientErrors.length > 0) {
      clientErrors.forEach(function (err) { showFieldError(err.field, err.message); });
      return;
    }

    /* Get Turnstile token */
    var turnstileInput = form.querySelector('[name="cf-turnstile-response"]');
    var turnstileToken = turnstileInput ? turnstileInput.value : '';
    if (!turnstileToken) {
      showFieldError('turnstileToken', 'Please complete the captcha verification');
      return;
    }

    setLoading(true);

    var payload = {
      name: form.querySelector('[name="name"]').value.trim(),
      email: form.querySelector('[name="email"]').value.trim(),
      message: form.querySelector('[name="message"]').value.trim(),
      turnstileToken: turnstileToken,
    };

    try {
      var res = await fetch('/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      var data = await res.json();

      if (!res.ok) {
        /* Field-level errors from server */
        if (data.fields && Array.isArray(data.fields)) {
          data.fields.forEach(function (err) { showFieldError(err.field, err.message); });
        }
        /* General error */
        errorBanner.textContent = data.error || 'Something went wrong. Please try again.';
        errorBanner.hidden = false;

        /* Reset Turnstile on failure so user can retry */
        if (typeof turnstile !== 'undefined') {
          turnstile.reset();
        }
        return;
      }

      /* Success */
      successBanner.textContent = data.message || 'Your message has been sent!';
      successBanner.hidden = false;
      form.reset();
      if (typeof turnstile !== 'undefined') {
        turnstile.reset();
      }
    } catch (err) {
      errorBanner.textContent = 'Network error. Please check your connection and try again.';
      errorBanner.hidden = false;
    } finally {
      setLoading(false);
    }
  });
})();
</script>

<style>
  .contact-form {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
    max-width: 36rem;
  }

  .contact-form__field {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .contact-form__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
  }

  .contact-form__input {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
    background-color: var(--color-bg);
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-4);
    transition: border-color var(--transition), box-shadow var(--transition);
  }

  .contact-form__input::placeholder {
    color: var(--color-stone);
  }

  .contact-form__input:focus {
    outline: none;
    border-color: var(--color-focus);
    box-shadow: 0 0 0 3px color-mix(in srgb, var(--color-focus) 25%, transparent);
  }

  .contact-form__input--error {
    border-color: var(--color-terracotta, #c0392b);
  }

  .contact-form__textarea {
    resize: vertical;
    min-height: 8rem;
  }

  .contact-form__error {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-terracotta, #c0392b);
    min-height: 0;
  }

  .contact-form__error:empty,
  .contact-form__error[hidden] {
    display: none;
  }

  .contact-form__submit {
    align-self: flex-start;
    display: inline-flex;
    align-items: center;
    gap: var(--space-2);
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    border: none;
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-8);
    cursor: pointer;
    transition: background-color var(--transition), box-shadow var(--transition), opacity var(--transition);
  }

  .contact-form__submit:hover:not(:disabled) {
    background-color: color-mix(in srgb, var(--color-terracotta) 85%, black);
  }

  .contact-form__submit:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .contact-form__submit:disabled {
    opacity: 0.7;
    cursor: not-allowed;
  }

  /* Spinner */
  .contact-form__spinner {
    display: none;
    width: 1em;
    height: 1em;
    border: 2px solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: contact-spin 0.6s linear infinite;
  }

  .contact-form__submit:disabled .contact-form__spinner {
    display: inline-block;
  }

  @keyframes contact-spin {
    to { transform: rotate(360deg); }
  }

  /* Banners */
  .contact-form__banner {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    padding: var(--space-3) var(--space-4);
    border-radius: var(--radius-sm);
  }

  .contact-form__banner[hidden] {
    display: none;
  }

  .contact-form__banner--error {
    color: #991b1b;
    background-color: #fef2f2;
    border: 1px solid #fecaca;
  }

  .contact-form__banner--success {
    color: #166534;
    background-color: #f0fdf4;
    border: 1px solid #bbf7d0;
  }
